import{c as t,S as h,j as a,m as i}from"./chunks/framework.8aa1YH_s.js";const p=JSON.parse('{"title":"Hồ sơ cá nhân (Học viên)","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/ho-so-ca-nhan.md","filePath":"hoc-vien/ho-so-ca-nhan.md","lastUpdated":0}'),o={name:"hoc-vien/ho-so-ca-nhan.md"};function c(l,n,r,g,s,e){return h(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="ho-so-ca-nhan-hoc-vien" tabindex="-1">Hồ sơ cá nhân (Học viên) <a class="header-anchor" href="#ho-so-ca-nhan-hoc-vien" aria-label="Permalink to “Hồ sơ cá nhân (Học viên)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/profile</code></p><p>Trang quản lý thông tin tài khoản của bạn.</p><h2 id="cac-tab-chinh" tabindex="-1">Các tab chính <a class="header-anchor" href="#cac-tab-chinh" aria-label="Permalink to “Các tab chính”">​</a></h2><table tabindex="0"><thead><tr><th>Tab</th><th>Mục đích</th></tr></thead><tbody><tr><td><strong>Thông tin cá nhân</strong></td><td>Họ tên, SĐT, email, ngày sinh, địa chỉ, khối lớp</td></tr><tr><td><strong>Đổi mật khẩu</strong></td><td>Thay mật khẩu định kỳ</td></tr><tr><td><strong>Khóa học của tôi</strong></td><td>Liên kết sang trang quản lý khóa</td></tr><tr><td><strong>Hóa đơn</strong></td><td>Lịch sử thanh toán</td></tr><tr><td><strong>Thông báo</strong></td><td>Cấu hình nhận thông báo</td></tr></tbody></table><h2 id="thong-tin-ca-nhan" tabindex="-1">Thông tin cá nhân <a class="header-anchor" href="#thong-tin-ca-nhan" aria-label="Permalink to “Thông tin cá nhân”">​</a></h2><p>Các trường:</p><ul><li><strong>Họ và tên</strong> (chính xác - sẽ hiển thị trong báo cáo điểm thi).</li><li><strong>Số điện thoại</strong> (đổi cần xác thực OTP).</li><li><strong>Email</strong> (đổi cần xác thực).</li><li><strong>Ngày sinh</strong>, <strong>Giới tính</strong>.</li><li><strong>Khối lớp</strong> (10/11/12).</li><li><strong>Tỉnh / Thành phố</strong>, <strong>Quận / Huyện</strong>, <strong>Trường</strong> đang học.</li><li><strong>Ảnh đại diện</strong>.</li></ul><p>Sau khi sửa → bấm <strong>Lưu</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Cập nhật trường đầy đủ</p><p>Trung tâm có thể dùng thông tin khối lớp và tỉnh để gửi <strong>gợi ý khóa học phù hợp</strong>. Càng đầy đủ, gợi ý càng đúng.</p></div><h2 id="đoi-mat-khau" tabindex="-1">Đổi mật khẩu <a class="header-anchor" href="#đoi-mat-khau" aria-label="Permalink to “Đổi mật khẩu”">​</a></h2><ol><li>Nhập <strong>Mật khẩu hiện tại</strong>.</li><li>Nhập <strong>Mật khẩu mới</strong> (≥ 8 ký tự).</li><li>Xác nhận lại mật khẩu mới.</li><li>Bấm <strong>Đổi mật khẩu</strong>.</li></ol><blockquote><p>Sau khi đổi, các thiết bị khác (nếu có) bị đăng xuất.</p></blockquote><h2 id="khoa-hoc-cua-toi" tabindex="-1">Khóa học của tôi <a class="header-anchor" href="#khoa-hoc-cua-toi" aria-label="Permalink to “Khóa học của tôi”">​</a></h2><p>Liên kết sang <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/khoa-hoc</code> để xem các khóa bạn đang sở hữu.</p><p>→ Xem <a href="./khoa-hoc-cua-toi">Khóa học của tôi</a>.</p><h2 id="hoa-đon" tabindex="-1">Hóa đơn <a class="header-anchor" href="#hoa-đon" aria-label="Permalink to “Hóa đơn”">​</a></h2><p>Liên kết sang <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/hoa-don</code> để xem lịch sử thanh toán.</p><p>Cột chính:</p><ul><li>Mã hóa đơn</li><li>Ngày tạo</li><li>Khóa học / sản phẩm</li><li>Tổng tiền</li><li>Phương thức</li><li>Trạng thái (Đã thanh toán / Đang chờ / Hủy)</li></ul><p>Bấm vào hóa đơn để xem chi tiết / tải PDF.</p><h2 id="thanh-tich-lich-su-thi" tabindex="-1">Thành tích &amp; Lịch sử thi <a class="header-anchor" href="#thanh-tich-lich-su-thi" aria-label="Permalink to “Thành tích &amp; Lịch sử thi”">​</a></h2><p>Tab này (nếu có) hiển thị:</p><ul><li>Tổng số bài đã làm.</li><li>Điểm cao nhất từng đạt.</li><li>Tỷ lệ đúng theo chủ đề.</li><li>Bảng xếp hạng (so với cộng đồng học viên).</li></ul><h2 id="thiet-bi-đang-nhap" tabindex="-1">Thiết bị đăng nhập <a class="header-anchor" href="#thiet-bi-đang-nhap" aria-label="Permalink to “Thiết bị đăng nhập”">​</a></h2><p>Xem các thiết bị đang dùng tài khoản. Có nút <strong>Đăng xuất khỏi thiết bị này</strong> khi thấy thiết bị lạ.</p><h2 id="thong-bao" tabindex="-1">Thông báo <a class="header-anchor" href="#thong-bao" aria-label="Permalink to “Thông báo”">​</a></h2><p>Bật / tắt:</p><ul><li>Email khi có bài giảng mới trong khóa đã mua.</li><li>Email khi giáo viên trả lời Hỏi đáp của bạn.</li><li>Email khi có khuyến mãi mới.</li><li>Push notification (nếu dùng app).</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi muốn đổi tên tài khoản nhưng không lưu được?</strong> → Một số trường khóa sau khi tạo tài khoản. Nếu cần đổi, liên hệ hotline trung tâm để hỗ trợ.</p><p><strong>Email của tôi sai - không nhận được hóa đơn / OTP?</strong> → Vào tab <strong>Thông tin cá nhân</strong> → sửa email → xác thực qua link kích hoạt.</p><p><strong>Tôi muốn xóa tài khoản vĩnh viễn?</strong> → Liên hệ trung tâm yêu cầu xóa. Mọi dữ liệu (lịch sử, khóa đã mua) sẽ bị xóa, không khôi phục được.</p>',33)])])}const u=t(o,[["render",c]]);export{p as __pageData,u as default};
